import{_ as r,C as s,o,c as i,a2 as e,E as l}from"./chunks/framework.BKG_UbFK.js";const _=JSON.parse('{"title":"Дашборд","description":"","frontmatter":{},"headers":[],"relativePath":"ru/features/dashboard.md","filePath":"ru/features/dashboard.md"}'),n={name:"ru/features/dashboard.md"};function d(c,a,h,u,p,g){const t=s("Screenshot");return o(),i("div",null,[a[0]||(a[0]=e('<h1 id="дашборд" tabindex="-1">Дашборд <a class="header-anchor" href="#дашборд" aria-label="Permalink to &quot;Дашборд&quot;">​</a></h1><p>Дашборд - это стартовая страница панели Clearance. Он даёт беглый обзор состояния авторизации вашего приложения - без необходимости какой-либо настройки.</p><h2 id="что-он-показывает" tabindex="-1">Что он показывает <a class="header-anchor" href="#что-он-показывает" aria-label="Permalink to &quot;Что он показывает&quot;">​</a></h2><ul><li><strong>Всего ролей</strong> - количество всех ролей Spatie.</li><li><strong>Всего guard&#39;ов</strong> - количество всех guard&#39;ов, управляемых Clearance (см. <a href="/clearance-docs/ru/features/guards.html">Guards</a>).</li><li><strong>Всего разрешений</strong> - количество всех разрешений Spatie.</li><li><strong>Группы разрешений</strong> - количество различных групп разрешений, определённых по префиксу именования (<code>group</code> в <code>group-action</code>, напр. <code>orders</code> в <code>orders-create</code>). См. <a href="/clearance-docs/ru/features/permissions.html">Разрешения</a> для соглашения об именовании.</li><li><strong>Контекстные назначения ролей</strong> - количество назначений ролей, привязанных к конкретному экземпляру модели (Store, Tenant, Project). См. <a href="/clearance-docs/ru/features/contextual-authorization.html">Контекстную авторизацию</a>.</li><li><strong>Топ-5 ролей по количеству пользователей</strong> - пять ролей с наибольшим числом назначенных пользователей, в рейтинге.</li></ul>',4)),l(t,{src:"/screenshots/dashboard-page.png",alt:"Дашборд Clearance с количеством ролей, guard'ов и разрешений",caption:"Дашборд суммирует роли, guard'ы, разрешения, группы, контекстные назначения и топ ролей."}),a[1]||(a[1]=e('<h2 id="доступ-к-дашборду" tabindex="-1">Доступ к Дашборду <a class="header-anchor" href="#доступ-к-дашборду" aria-label="Permalink to &quot;Доступ к Дашборду&quot;">​</a></h2><table tabindex="0"><thead><tr><th>URI</th><th>Имя маршрута</th><th>Описание</th></tr></thead><tbody><tr><td><code>/clearance</code></td><td><code>clearance.home</code></td><td>Дашборд</td></tr></tbody></table><p>Чтение Дашборда требует разрешения <code>clearance-access</code>, как и любой другой раздел панели. См. <a href="/clearance-docs/ru/features/super-admin.html#panel-access-fine-grained-write-permissions">Super Admin</a> для полной таблицы контроля доступа.</p><h2 id="встраивание-компонента" tabindex="-1">Встраивание компонента <a class="header-anchor" href="#встраивание-компонента" aria-label="Permalink to &quot;Встраивание компонента&quot;">​</a></h2><p>Дашборд - это самодостаточный Livewire-компонент. Подключите его в любом месте ваших собственных layout&#39;ов вместо готового маршрута <code>/clearance</code> или в дополнение к нему:</p><div class="language-blade vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">blade</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">livewire:clearance::dashboard</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre></div><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><ul><li><a href="/clearance-docs/ru/features/permissions.html">Разрешения</a> - управление списком разрешений, из которого формируются счётчики Дашборда.</li><li><a href="/clearance-docs/ru/features/roles.html">Роли</a> - управление ролями, стоящими за статистикой &quot;топ-5 по числу пользователей&quot;.</li><li><a href="/clearance-docs/ru/features/contextual-authorization.html">Контекстная авторизация</a> - что такое контекстное назначение роли.</li></ul>',8))])}const m=r(n,[["render",d]]);export{_ as __pageData,m as default};
